	for _, ev := range events {
		if ev.Kind == NoChangesEventOperatorRequired {
			sawOperator = true
			assert.Contains(t, ev.Body, "status=proposed")
		}
	}
	assert.True(t, sawOperator, "no_changes_operator_required event must be emitted")
}

