	// no-candidate iteration (ddx-dc157075 AC #5).
	if wasIdle && runtime.Log != nil {
		_, _ = fmt.Fprint(runtime.Log, workLog.FormatNextReadyTransition(candidate.ID, candidate.Title))
	}
