	WorkerReady       int `json:"worker_ready"`
	DependencyWaiting int `json:"dependency_waiting"`
	ExternalBlocked   int `json:"external_blocked"`
	OperatorAttention int `json:"operator_attention"`
	Total             int `json:"total"`
}

